namespace Domain.Models;

/// <summary>
/// Represents a chat message bookmarked (saved) by a user for later reference.
/// </summary>
public class ChatSavedMessage : Entity<int>
{
    /// <summary>Gets or sets the user who saved the message.</summary>
    public int UserId { get; set; }

    /// <summary>Gets or sets the user navigation property.</summary>
    public AppUser User { get; set; } = default!;

    /// <summary>Gets or sets the saved chat message identifier.</summary>
    public int MessageId { get; set; }

    /// <summary>Gets or sets the saved chat message navigation property.</summary>
    public ChatMessage Message { get; set; } = default!;
}

using Domain.Models;
using Microsoft.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore.Metadata.Builders;

namespace Infrastructure.Data.Configuration;

/// <summary>
/// Configures the <see cref="ChatSavedMessage"/> entity mapping, constraints, and relationships.
/// </summary>
public class ChatSavedMessageConfiguration : IEntityTypeConfiguration<ChatSavedMessage>
{
    /// <inheritdoc />
    public void Configure(EntityTypeBuilder<ChatSavedMessage> builder)
    {
        builder.ToTable("Chat_SavedMessages");

        builder.HasOne(s => s.User)
            .WithMany()
            .HasForeignKey(s => s.UserId)
            .OnDelete(DeleteBehavior.NoAction);

        builder.HasOne(s => s.Message)
            .WithMany()
            .HasForeignKey(s => s.MessageId)
            .OnDelete(DeleteBehavior.NoAction);

        builder.HasIndex(s => new { s.UserId, s.MessageId })
            .IsUnique();
    }
}

namespace Application.DTOs.Chat;

/// <summary>
/// Data transfer object representing a saved chat message for the current user.
/// </summary>
public class SavedChatMessageDto
{
    /// <summary>Gets or sets when the message was saved by the current user.</summary>
    public DateTime SavedAt { get; set; }

    /// <summary>Gets or sets the conversation identifier the message belongs to.</summary>
    public int ConversationId { get; set; }

    /// <summary>Gets or sets the conversation display name at save-list time.</summary>
    public string ConversationName { get; set; } = string.Empty;

    /// <summary>Gets or sets the conversation type (Pv, Group, Channel).</summary>
    public string ConversationType { get; set; } = string.Empty;

    /// <summary>Gets or sets the saved message payload.</summary>
    public ChatMessageDto Message { get; set; } = default!;
}

namespace Application.Features.App.Chat.Messages.Commands.SaveChatMessage;

/// <summary>
/// Command to save (bookmark) a chat message for the current user.
/// </summary>
/// <param name="MessageId">The identifier of the message to save.</param>
public record SaveChatMessageCommand(int MessageId) : IRequest<Result>;

/// <summary>
/// Validates the <see cref="SaveChatMessageCommand"/> input.
/// </summary>
public class SaveChatMessageCommandValidator : AbstractValidator<SaveChatMessageCommand>
{
    public SaveChatMessageCommandValidator()
    {
        RuleFor(x => x.MessageId)
            .GreaterThan(0).WithMessage("شناسه پیام نامعتبر است");
    }
}

using Application.Services.Interface;

namespace Application.Features.App.Chat.Messages.Commands.SaveChatMessage;

/// <summary>
/// Handles <see cref="SaveChatMessageCommand"/> by bookmarking a chat message for the current user.
/// </summary>
public class SaveChatMessageCommandHandler(
    IApplicationDbContext context,
    ICurrentUserService currentUserService)
    : IRequestHandler<SaveChatMessageCommand, Result>
{
    /// <summary>
    /// Saves a chat message for the authenticated user when they are a conversation participant.
    /// </summary>
    /// <param name="request">The validated save command.</param>
    /// <param name="cancellationToken">Token to observe for cancellation requests.</param>
    /// <returns><see cref="Result.Success()"/> when saved or already saved; otherwise a domain error.</returns>
    public async Task<Result> Handle(
        SaveChatMessageCommand request,
        CancellationToken cancellationToken)
    {
        try
        {
            int currentUserId = currentUserService.UserId();

            var message = await context.ChatMessages
                .AsNoTracking()
                .FirstOrDefaultAsync(m => m.Id == request.MessageId, cancellationToken);

            if (message is null)
                return ChatErrors.MessageNotFound;

            if (message.IsDeleted)
                return ChatErrors.MessageIsDeleted;

            var isMember = await context.ChatParticipants
                .AsNoTracking()
                .AnyAsync(p =>
                    p.ConversationId == message.ConversationId
                    && p.UserId == currentUserId
                    && p.LeftAt == null,
                    cancellationToken);

            if (!isMember)
                return ChatErrors.NotAParticipant;

            var existing = await context.ChatSavedMessages
                .IgnoreQueryFilters()
                .FirstOrDefaultAsync(s =>
                    s.UserId == currentUserId
                    && s.MessageId == request.MessageId,
                    cancellationToken);

            if (existing is not null)
            {
                if (!existing.IsDeleted)
                    return Result.Success();

                existing.IsDeleted = false;
                existing.DeleteBy = null;
                existing.DeleteDate = null;
            }
            else
            {
                await context.ChatSavedMessages.AddAsync(new ChatSavedMessage
                {
                    UserId = currentUserId,
                    MessageId = request.MessageId
                }, cancellationToken);
            }

            await context.SaveChangesAsync(cancellationToken);

            return Result.Success();
        }
        catch (Exception ex)
        {
            Log.Error($"CQRS (SaveChatMessage): {ex.Message}", ex);
            return Error.ServerError;
        }
    }
}

namespace Application.Features.App.Chat.Messages.Commands.UnsaveChatMessage;

/// <summary>
/// Command to remove a previously saved chat message bookmark for the current user.
/// </summary>
/// <param name="MessageId">The identifier of the message to unsave.</param>
public record UnsaveChatMessageCommand(int MessageId) : IRequest<Result>;

/// <summary>
