/// </summary>
public class UnsaveChatMessageCommandValidator : AbstractValidator<UnsaveChatMessageCommand>
{
    public UnsaveChatMessageCommandValidator()
    {
        RuleFor(x => x.MessageId)
            .GreaterThan(0).WithMessage("شناسه پیام نامعتبر است");
    }
}

using Application.Services.Interface;

namespace Application.Features.App.Chat.Messages.Commands.UnsaveChatMessage;

/// <summary>
/// Handles <see cref="UnsaveChatMessageCommand"/> by soft-deleting a saved-message bookmark.
/// </summary>
public class UnsaveChatMessageCommandHandler(
    IApplicationDbContext context,
    ICurrentUserService currentUserService)
    : IRequestHandler<UnsaveChatMessageCommand, Result>
{
    /// <summary>
    /// Removes a saved-message bookmark for the authenticated user.
    /// </summary>
    /// <param name="request">The validated unsave command.</param>
    /// <param name="cancellationToken">Token to observe for cancellation requests.</param>
    /// <returns><see cref="Result.Success()"/> when unsaved; otherwise a domain error.</returns>
    public async Task<Result> Handle(
        UnsaveChatMessageCommand request,
        CancellationToken cancellationToken)
    {
        try
        {
            int currentUserId = currentUserService.UserId();

            var saved = await context.ChatSavedMessages
                .FirstOrDefaultAsync(s =>
                    s.UserId == currentUserId
                    && s.MessageId == request.MessageId,
                    cancellationToken);

            if (saved is null)
                return ChatErrors.MessageNotSaved;

            saved.IsDeleted = true;
            saved.DeleteBy = currentUserService.Username();
            if (string.IsNullOrWhiteSpace(saved.DeleteBy))
                saved.DeleteBy = "unknown";
            saved.DeleteDate = DateTime.Now;

            await context.SaveChangesAsync(cancellationToken);

            return Result.Success();
        }
        catch (Exception ex)
        {
            Log.Error($"CQRS (UnsaveChatMessage): {ex.Message}", ex);
            return Error.ServerError;
        }
    }
}

