namespace Application.Features.App.Chat.Messages.Queries.GetSavedChatMessages;

/// <summary>
/// Query to retrieve a paginated list of chat messages saved by the current user.
/// </summary>
/// <param name="Request">Pagination parameters (zero-based PageIndex, PageSize).</param>
public record GetSavedChatMessagesQuery(PaginationRequest Request)
    : IRequest<Result<PaginatedResult<SavedChatMessageDto>>>;

using Application.DTOs.Chat;
using Application.Services.Interface;

namespace Application.Features.App.Chat.Messages.Queries.GetSavedChatMessages;

/// <summary>
/// Handles <see cref="GetSavedChatMessagesQuery"/> by returning saved messages for the current user.
/// </summary>
public class GetSavedChatMessagesQueryHandler(
    IApplicationDbContext context,
    ICurrentUserService currentUserService)
    : IRequestHandler<GetSavedChatMessagesQuery, Result<PaginatedResult<SavedChatMessageDto>>>
{
    /// <summary>
    /// Executes the paginated saved-messages query ordered by most recently saved first.
    /// </summary>
    /// <param name="request">The query containing pagination parameters.</param>
    /// <param name="cancellationToken">Token to observe for cancellation requests.</param>
    /// <returns>
    /// A <see cref="Result{T}"/> containing a <see cref="PaginatedResult{T}"/> of
    /// <see cref="SavedChatMessageDto"/> on success, or <see cref="Error.ServerError"/> on failure.
    /// </returns>
    public async Task<Result<PaginatedResult<SavedChatMessageDto>>> Handle(
        GetSavedChatMessagesQuery request,
        CancellationToken cancellationToken)
    {
        try
        {
            int currentUserId = currentUserService.UserId();

            var qBase = context.ChatSavedMessages
                .AsNoTracking()
                .Where(s => s.UserId == currentUserId);

            int totalCount = await qBase.CountAsync(cancellationToken);

            var items = await qBase
                .OrderByDescending(s => s.CreateDate)
                .ThenByDescending(s => s.Id)
                .Pagination(request.Request)
                .Select(s => new
                {
                    SavedAt = s.CreateDate,
                    s.MessageId,
                    s.Message.ConversationId,
                    ConversationName = s.Message.Conversation.Name,
                    ConversationType = s.Message.Conversation.Type,
                    Message = new
                    {
                        s.Message.Id,
                        s.Message.ConversationId,
                        s.Message.SenderId,
                        SenderName = s.Message.Sender.Name,
                        SenderAvatarUrl = s.Message.Sender.ProfileImage,
                        s.Message.Text,
                        s.Message.IsDeleted,
                        s.Message.IsEdited,
                        s.Message.EditedAt,
                        SentAt = s.Message.CreateDate,
                        s.Message.ReplyToMessageId,
                        ReplyToSenderName = s.Message.ReplyToMessage != null
                            ? s.Message.ReplyToMessage.Sender.Name
                            : null,
                        ReplyToText = s.Message.ReplyToMessage != null
                            ? s.Message.ReplyToMessage.Text
                            : null,
                        ReplyToIsDeleted = s.Message.ReplyToMessage != null
                            && s.Message.ReplyToMessage.IsDeleted,
                        s.Message.ForwardedFromSenderName,
                        s.Message.ForwardedFromSentAt,
                        Attachments = s.Message.Attachments.Select(a => new
                        {
                            a.Id,
                            a.FileName,
                            a.FileUrl,
                            a.FileSize,
                            a.ContentType
                        }).ToList()
                    }
                })
                .ToListAsync(cancellationToken);

            var dtos = items.Select(s => new SavedChatMessageDto
            {
                SavedAt = s.SavedAt,
                ConversationId = s.ConversationId,
                ConversationName = s.ConversationName,
                ConversationType = s.ConversationType.ToString(),
                Message = new ChatMessageDto
                {
                    Id = s.Message.Id,
                    ConversationId = s.Message.ConversationId,
                    SenderId = s.Message.SenderId,
                    SenderName = s.Message.SenderName,
                    SenderAvatarUrl = string.IsNullOrEmpty(s.Message.SenderAvatarUrl)
                        ? null
                        : s.Message.SenderAvatarUrl,
                    Text = s.Message.IsDeleted ? null : s.Message.Text,
                    IsDeleted = s.Message.IsDeleted,
                    IsEdited = s.Message.IsEdited,
                    SentAt = s.Message.SentAt,
                    EditedAt = s.Message.EditedAt,
                    IsSavedByMe = true,
                    ReplyTo = s.Message.ReplyToMessageId.HasValue
                        ? new ChatMessageReplySnapshotDto
                        {
                            MessageId = s.Message.ReplyToMessageId.Value,
                            SenderName = s.Message.ReplyToSenderName ?? string.Empty,
                            TextPreview = s.Message.ReplyToIsDeleted
                                ? null
                                : TruncatePreview(s.Message.ReplyToText),
                            IsDeleted = s.Message.ReplyToIsDeleted
                        }
                        : null,
                    ForwardedFrom = !string.IsNullOrEmpty(s.Message.ForwardedFromSenderName)
                        ? new ForwardedFromDto
                        {
                            OriginalSenderName = s.Message.ForwardedFromSenderName,
                            OriginalSentAt = s.Message.ForwardedFromSentAt ?? s.Message.SentAt
                        }
                        : null,
                    Attachments = s.Message.Attachments.Select(a => new ChatFileDto
                    {
                        Id = a.Id,
                        FileName = a.FileName,
                        FileUrl = a.FileUrl,
                        FileSize = a.FileSize,
                        ContentType = a.ContentType
                    }).ToList()
                }
            }).ToList();

            var pagedResult = new PaginatedResult<SavedChatMessageDto>(
                dtos,
                request.Request.PageIndex,
                request.Request.PageSize,
                dtos.Count,
                totalCount);

            return Result<PaginatedResult<SavedChatMessageDto>>.Success(pagedResult);
        }
        catch (Exception ex)
        {
            Log.Error($"CQRS (GetSavedChatMessages): {ex.Message}", ex);
            return Error.ServerError;
        }
    }

    private static string? TruncatePreview(string? text)
    {
        if (string.IsNullOrEmpty(text))
            return null;

        return text.Length <= 100 ? text : text[..100];
    }
}

