namespace Api.EndPoint.Chat;

/// <summary>
/// Endpoint for saving (bookmarking) a chat message for the current user.
/// </summary>
public class SaveChatMessageEndPoint : ICarterModule
{
    /// <summary>
    /// Registers the save-message route in the application pipeline.
    /// </summary>
    /// <param name="app">The endpoint route builder.</param>
    public void AddRoutes(IEndpointRouteBuilder app)
    {
        app.MapPost("/chat/messages/{messageId:int}/save", async (
            int messageId,
            ISender sender,
            CancellationToken cancellationToken) =>
        {
            var res = await sender.Send(new SaveChatMessageCommand(messageId), cancellationToken);

            if (res.IsSuccess)
                return Results.Ok();
            return Results.Problem(res!.Error!.Description, statusCode: 400);
        })
        .WithName("SaveChatMessage")
        .WithTags("Chat")
        .Produces(StatusCodes.Status200OK)
        .ProducesProblem(StatusCodes.Status400BadRequest)
        .WithSummary("Save chat message")
        .WithDescription("Bookmarks a chat message for the authenticated user. Idempotent when already saved.")
        .RequireRateLimiting(RateLimitConst.RateFix)
        .RequireAuthorization()
        .DisableAntiforgery();
    }
}

