namespace Api.EndPoint.Chat;

/// <summary>
/// Endpoint for listing chat messages saved by the current user.
/// </summary>
public class GetSavedChatMessagesEndPoint : ICarterModule
{
    /// <summary>
    /// Registers the saved-messages list route in the application pipeline.
    /// </summary>
    /// <param name="app">The endpoint route builder.</param>
    public void AddRoutes(IEndpointRouteBuilder app)
    {
        app.MapGet("/chat/messages/saved", async (
            [AsParameters] PaginationRequest request,
            ISender sender,
            CancellationToken cancellationToken) =>
        {
            var res = await sender.Send(new GetSavedChatMessagesQuery(request), cancellationToken);

            if (res.IsSuccess)
                return Results.Ok(res.Value);
            return Results.Problem(res!.Error!.Description, statusCode: 400);
        })
        .WithName("GetSavedChatMessages")
        .WithTags("Chat")
        .Produces<PaginatedResult<SavedChatMessageDto>>(StatusCodes.Status200OK)
        .ProducesProblem(StatusCodes.Status400BadRequest)
        .WithSummary("Get saved chat messages")
        .WithDescription("Returns a paginated list of chat messages bookmarked by the authenticated user.")
        .RequireRateLimiting(RateLimitConst.RateFix)
        .RequireAuthorization()
        .DisableAntiforgery();
    }
}

