namespace Domain.Models;

/// <summary>
/// Represents a message pinned in a chat conversation (visible to all participants).
/// </summary>
public class ChatPinnedMessage : Entity<int>
{
    /// <summary>Gets or sets the conversation identifier.</summary>
    public int ConversationId { get; set; }

    /// <summary>Gets or sets the conversation navigation property.</summary>
    public ChatConversation Conversation { get; set; } = default!;

    /// <summary>Gets or sets the pinned message identifier.</summary>
    public int MessageId { get; set; }

    /// <summary>Gets or sets the pinned message navigation property.</summary>
    public ChatMessage Message { get; set; } = default!;

    /// <summary>Gets or sets the user who pinned the message.</summary>
    public int PinnedByUserId { get; set; }

    /// <summary>Gets or sets the user who pinned the message.</summary>
    public AppUser PinnedByUser { get; set; } = default!;
}

namespace Application.Features.App.Chat.Messages;

/// <summary>
/// Shared constants for chat message pin operations.
/// </summary>
public static class ChatPinConstants
{
    /// <summary>Maximum number of pinned messages allowed per conversation.</summary>
    public const int MaxPinsPerConversation = 20;
}

namespace Application.Features.App.Chat.Messages;

/// <summary>
/// Evaluates whether a conversation participant may pin or unpin messages.
/// </summary>
public static class ChatPinPermissionHelper
{
    /// <summary>
    /// Returns true when the participant may pin or unpin in the given conversation type.
    /// Channel requires <see cref="ChatParticipantRole.Admin"/>; PV and Group allow any active member.
    /// </summary>
    public static bool CanPinOrUnpin(ChatConversationType conversationType, ChatParticipantRole role)
    {
        return conversationType != ChatConversationType.Channel
               || role == ChatParticipantRole.Admin;
    }
}

using Application.DTOs.Chat;

namespace Application.Features.App.Chat.Messages;

/// <summary>
/// Maps chat message projection data to <see cref="ChatMessageDto"/>.
/// </summary>
internal static class ChatMessageDtoMapper
{
    internal sealed class MessageProjection
    {
        public int Id { get; init; }
        public int ConversationId { get; init; }
        public int SenderId { get; init; }
        public string SenderName { get; init; } = string.Empty;
        public string? SenderAvatarUrl { get; init; }
        public string? Text { get; init; }
        public bool IsDeleted { get; init; }
        public bool IsEdited { get; init; }
        public DateTime? EditedAt { get; init; }
        public DateTime SentAt { get; init; }
        public int? ReplyToMessageId { get; init; }
        public string? ReplyToSenderName { get; init; }
        public string? ReplyToText { get; init; }
        public bool ReplyToIsDeleted { get; init; }
        public string? ForwardedFromSenderName { get; init; }
        public DateTime? ForwardedFromSentAt { get; init; }
        public List<AttachmentProjection> Attachments { get; init; } = [];
        public bool IsPinned { get; init; }
        public bool IsSavedByMe { get; init; }
    }

    internal sealed class AttachmentProjection
    {
        public int Id { get; init; }
        public string FileName { get; init; } = string.Empty;
        public string FileUrl { get; init; } = string.Empty;
        public long FileSize { get; init; }
        public string ContentType { get; init; } = string.Empty;
    }

    internal static ChatMessageDto ToDto(MessageProjection m) =>
        new()
        {
            Id = m.Id,
            ConversationId = m.ConversationId,
            SenderId = m.SenderId,
            SenderName = m.SenderName,
            SenderAvatarUrl = string.IsNullOrEmpty(m.SenderAvatarUrl) ? null : m.SenderAvatarUrl,
            Text = m.IsDeleted ? null : m.Text,
            IsDeleted = m.IsDeleted,
            IsEdited = m.IsEdited,
            SentAt = m.SentAt,
            EditedAt = m.EditedAt,
            IsPinned = m.IsPinned,
            IsSavedByMe = m.IsSavedByMe,
            ReplyTo = m.ReplyToMessageId.HasValue
                ? new ChatMessageReplySnapshotDto
                {
                    MessageId = m.ReplyToMessageId.Value,
                    SenderName = m.ReplyToSenderName ?? string.Empty,
                    TextPreview = m.ReplyToIsDeleted ? null : TruncatePreview(m.ReplyToText),
                    IsDeleted = m.ReplyToIsDeleted
                }
                : null,
            ForwardedFrom = !string.IsNullOrEmpty(m.ForwardedFromSenderName)
                ? new ForwardedFromDto
                {
                    OriginalSenderName = m.ForwardedFromSenderName,
                    OriginalSentAt = m.ForwardedFromSentAt ?? m.SentAt
                }
                : null,
            Attachments = m.Attachments.Select(a => new ChatFileDto
            {
                Id = a.Id,
                FileName = a.FileName,
                FileUrl = a.FileUrl,
                FileSize = a.FileSize,
                ContentType = a.ContentType
            }).ToList()
        };

    internal static string? TruncatePreview(string? text)
    {
        if (string.IsNullOrEmpty(text))
            return null;

        return text.Length <= 100 ? text : text[..100];
    }
}

namespace Application.Features.App.Chat.Messages.Commands.PinChatMessage;

