{
    public PinChatMessageCommandValidator()
    {
        RuleFor(x => x.ConversationId)
            .GreaterThan(0).WithMessage("شناسه مکالمه نامعتبر است");

        RuleFor(x => x.MessageId)
            .GreaterThan(0).WithMessage("شناسه پیام نامعتبر است");
    }
