namespace Application.Features.App.Chat.Messages.Commands.PinChatMessage;

/// <summary>
/// Handles <see cref="PinChatMessageCommand"/> by pinning a message in a conversation.
/// </summary>
public class PinChatMessageCommandHandler(
    IApplicationDbContext context,
    ICurrentUserService currentUserService,
    IChatNotificationService chatNotificationService)
    : IRequestHandler<PinChatMessageCommand, Result>
{
    /// <summary>
    /// Pins a message when the caller is an authorized participant and the pin limit is not exceeded.
    /// </summary>
    /// <param name="request">The validated pin command.</param>
    /// <param name="cancellationToken">Token to observe for cancellation requests.</param>
    /// <returns><see cref="Result.Success()"/> when pinned or already pinned; otherwise a domain error.</returns>
    public async Task<Result> Handle(
        PinChatMessageCommand request,
        CancellationToken cancellationToken)
    {
        try
        {
            int currentUserId = currentUserService.UserId();

            var conversation = await context.ChatConversations
                .AsNoTracking()
                .FirstOrDefaultAsync(c => c.Id == request.ConversationId, cancellationToken);

            if (conversation is null)
                return ChatErrors.ConversationNotFound;

            var participant = await context.ChatParticipants
                .AsNoTracking()
                .FirstOrDefaultAsync(p =>
                    p.ConversationId == request.ConversationId
                    && p.UserId == currentUserId
                    && p.LeftAt == null,
                    cancellationToken);

            if (participant is null)
                return ChatErrors.NotAParticipant;

            if (!ChatPinPermissionHelper.CanPinOrUnpin(conversation.Type, participant.Role))
                return ChatErrors.NotChannelAdmin;

            var message = await context.ChatMessages
                .AsNoTracking()
                .FirstOrDefaultAsync(m => m.Id == request.MessageId, cancellationToken);

            if (message is null)
                return ChatErrors.MessageNotFound;

            if (message.ConversationId != request.ConversationId)
                return ChatErrors.MessageNotInConversation;

            if (message.IsDeleted)
                return ChatErrors.MessageIsDeleted;

            var existing = await context.ChatPinnedMessages
                .IgnoreQueryFilters()
                .FirstOrDefaultAsync(p =>
                    p.ConversationId == request.ConversationId
                    && p.MessageId == request.MessageId,
                    cancellationToken);

            if (existing is not null)
            {
                if (!existing.IsDeleted)
                    return Result.Success();

                existing.IsDeleted = false;
                existing.DeleteBy = null;
                existing.DeleteDate = null;
                existing.PinnedByUserId = currentUserId;
            }
            else
            {
                int pinCount = await context.ChatPinnedMessages
                    .CountAsync(p => p.ConversationId == request.ConversationId, cancellationToken);

                if (pinCount >= ChatPinConstants.MaxPinsPerConversation)
                    return ChatErrors.PinLimitReached;

                await context.ChatPinnedMessages.AddAsync(new ChatPinnedMessage
                {
                    ConversationId = request.ConversationId,
                    MessageId = request.MessageId,
                    PinnedByUserId = currentUserId
                }, cancellationToken);
            }

            await context.SaveChangesAsync(cancellationToken);

            var messageDto = await ChatMessageProjectionLoader.LoadMessageDtoAsync(
                context,
                request.MessageId,
                currentUserId,
                isPinned: true,
                cancellationToken);

            if (messageDto is not null)
            {
                await chatNotificationService.MessagePinnedAsync(
                    request.ConversationId,
                    messageDto,
                    currentUserId,
                    cancellationToken);
            }

            return Result.Success();
        }
        catch (Exception ex)
        {
            Log.Error($"CQRS (PinChatMessage): {ex.Message}", ex);
            return Error.ServerError;
        }
    }
}

