    IApplicationDbContext context,
    ICurrentUserService currentUserService,
    IChatNotificationService chatNotificationService)
    : IRequestHandler<UnpinChatMessageCommand, Result>
{
    /// <summary>
    /// Unpins a message when the caller is an authorized participant.
    /// </summary>
    /// <param name="request">The validated unpin command.</param>
    /// <param name="cancellationToken">Token to observe for cancellation requests.</param>
    /// <returns><see cref="Result.Success()"/> when unpinned; otherwise a domain error.</returns>
    public async Task<Result> Handle(
        UnpinChatMessageCommand request,
        CancellationToken cancellationToken)
    {
        try
        {
            int currentUserId = currentUserService.UserId();

            var conversation = await context.ChatConversations
                .AsNoTracking()
                .FirstOrDefaultAsync(c => c.Id == request.ConversationId, cancellationToken);

            if (conversation is null)
                return ChatErrors.ConversationNotFound;

            var participant = await context.ChatParticipants
                .AsNoTracking()
                .FirstOrDefaultAsync(p =>
                    p.ConversationId == request.ConversationId
                    && p.UserId == currentUserId
                    && p.LeftAt == null,
                    cancellationToken);

            if (participant is null)
                return ChatErrors.NotAParticipant;

            if (!ChatPinPermissionHelper.CanPinOrUnpin(conversation.Type, participant.Role))
                return ChatErrors.NotChannelAdmin;

            var pin = await context.ChatPinnedMessages
                .FirstOrDefaultAsync(p =>
                    p.ConversationId == request.ConversationId
                    && p.MessageId == request.MessageId,
