namespace Application.Features.App.Chat.Messages.Queries.GetPinnedChatMessages;

/// <summary>
/// Handles <see cref="GetPinnedChatMessagesQuery"/> by returning pinned messages for a conversation.
/// </summary>
public class GetPinnedChatMessagesQueryHandler(
    IApplicationDbContext context,
    ICurrentUserService currentUserService)
    : IRequestHandler<GetPinnedChatMessagesQuery, Result<List<PinnedChatMessageDto>>>
{
    /// <summary>
    /// Executes the pinned-messages query ordered by most recently pinned first.
    /// </summary>
    /// <param name="request">The query containing the conversation identifier.</param>
    /// <param name="cancellationToken">Token to observe for cancellation requests.</param>
    /// <returns>
    /// A <see cref="Result{T}"/> containing a list of <see cref="PinnedChatMessageDto"/>
    /// on success, or <see cref="Error.ServerError"/> on failure.
    /// </returns>
    public async Task<Result<List<PinnedChatMessageDto>>> Handle(
        GetPinnedChatMessagesQuery request,
        CancellationToken cancellationToken)
    {
        try
        {
            int currentUserId = currentUserService.UserId();

            var isMember = await context.ChatParticipants
                .AsNoTracking()
                .AnyAsync(p =>
                    p.ConversationId == request.ConversationId
                    && p.UserId == currentUserId
                    && p.LeftAt == null,
                    cancellationToken);

            if (!isMember)
                return ChatErrors.NotAParticipant;

            var pins = await context.ChatPinnedMessages
                .AsNoTracking()
                .Where(p => p.ConversationId == request.ConversationId)
                .OrderByDescending(p => p.CreateDate)
                .ThenByDescending(p => p.Id)
                .Select(p => new
                {
                    PinnedAt = p.CreateDate,
                    p.PinnedByUserId,
                    PinnedByUserName = p.PinnedByUser.Name,
                    Message = new
                    {
                        p.Message.Id,
                        p.Message.ConversationId,
                        p.Message.SenderId,
                        SenderName = p.Message.Sender.Name,
                        SenderAvatarUrl = p.Message.Sender.ProfileImage,
                        p.Message.Text,
                        p.Message.IsDeleted,
                        p.Message.IsEdited,
                        p.Message.EditedAt,
                        SentAt = p.Message.CreateDate,
                        p.Message.ReplyToMessageId,
                        ReplyToSenderName = p.Message.ReplyToMessage != null
                            ? p.Message.ReplyToMessage.Sender.Name
                            : null,
                        ReplyToText = p.Message.ReplyToMessage != null
                            ? p.Message.ReplyToMessage.Text
                            : null,
                        ReplyToIsDeleted = p.Message.ReplyToMessage != null
                            && p.Message.ReplyToMessage.IsDeleted,
                        p.Message.ForwardedFromSenderName,
                        p.Message.ForwardedFromSentAt,
                        Attachments = p.Message.Attachments.Select(a => new ChatMessageDtoMapper.AttachmentProjection
                        {
                            Id = a.Id,
                            FileName = a.FileName,
                            FileUrl = a.FileUrl,
                            FileSize = a.FileSize,
                            ContentType = a.ContentType
                        }).ToList()
                    }
                })
                .ToListAsync(cancellationToken);

            var messageIds = pins.Select(p => p.Message.Id).ToList();
            var savedIds = messageIds.Count == 0
                ? []
                : await context.ChatSavedMessages
                    .AsNoTracking()
                    .Where(s => s.UserId == currentUserId && messageIds.Contains(s.MessageId))
                    .Select(s => s.MessageId)
                    .ToListAsync(cancellationToken);

            var savedSet = savedIds.ToHashSet();

            var dtos = pins.Select(p => new PinnedChatMessageDto
            {
                PinnedAt = p.PinnedAt,
                PinnedByUserId = p.PinnedByUserId,
                PinnedByUserName = p.PinnedByUserName,
                Message = ChatMessageDtoMapper.ToDto(new ChatMessageDtoMapper.MessageProjection
                {
                    Id = p.Message.Id,
                    ConversationId = p.Message.ConversationId,
                    SenderId = p.Message.SenderId,
                    SenderName = p.Message.SenderName,
                    SenderAvatarUrl = p.Message.SenderAvatarUrl,
                    Text = p.Message.Text,
                    IsDeleted = p.Message.IsDeleted,
                    IsEdited = p.Message.IsEdited,
                    EditedAt = p.Message.EditedAt,
                    SentAt = p.Message.SentAt,
                    ReplyToMessageId = p.Message.ReplyToMessageId,
                    ReplyToSenderName = p.Message.ReplyToSenderName,
                    ReplyToText = p.Message.ReplyToText,
                    ReplyToIsDeleted = p.Message.ReplyToIsDeleted,
                    ForwardedFromSenderName = p.Message.ForwardedFromSenderName,
                    ForwardedFromSentAt = p.Message.ForwardedFromSentAt,
                    Attachments = p.Message.Attachments,
                    IsPinned = true,
                    IsSavedByMe = savedSet.Contains(p.Message.Id)
                })
            }).ToList();

            return Result<List<PinnedChatMessageDto>>.Success(dtos);
        }
        catch (Exception ex)
        {
            Log.Error($"CQRS (GetPinnedChatMessages): {ex.Message}", ex);
            return Error.ServerError;
        }
    }
}

