namespace Api.EndPoint.Chat;

/// <summary>
/// Endpoint for pinning a chat message in a conversation.
/// </summary>
public class PinChatMessageEndPoint : ICarterModule
{
    /// <summary>
    /// Registers the pin-message route in the application pipeline.
    /// </summary>
    /// <param name="app">The endpoint route builder.</param>
    public void AddRoutes(IEndpointRouteBuilder app)
    {
        app.MapPost("/chat/conversations/{conversationId:int}/messages/{messageId:int}/pin", async (
            int conversationId,
            int messageId,
            ISender sender,
            CancellationToken cancellationToken) =>
        {
            var res = await sender.Send(
                new PinChatMessageCommand(conversationId, messageId),
                cancellationToken);

            if (res.IsSuccess)
                return Results.Ok();
            return Results.Problem(res!.Error!.Description, statusCode: 400);
        })
        .WithName("PinChatMessage")
        .WithTags("Chat")
        .Produces(StatusCodes.Status200OK)
        .ProducesProblem(StatusCodes.Status400BadRequest)
        .WithSummary("Pin chat message")
        .WithDescription("Pins a message in a conversation for all participants. Idempotent when already pinned.")
        .RequireRateLimiting(RateLimitConst.RateFix)
        .RequireAuthorization()
        .DisableAntiforgery();
    }
}

