                "pm.test('isSavedByMe true', () => pm.expect(m.isSavedByMe).to.eql(true));"
              ]
            }
          }],
          "request": {
            "method": "GET",
            "header": [{ "key": "Authorization", "value": "Bearer {{token_u1}}" }],
